"use client";

import { useState, useMemo } from "react";
import axios from "axios";
import { 
  Loader2, Search, ArrowLeftRight, CheckCircle, Users, Bed, 
  AlertCircle, ShieldCheck, X, Building2, UserPlus, History, 
  Filter, UserCheck, RefreshCw, ChevronRight, ArrowRight, Home,
  Sparkles, Layers
} from "lucide-react";
import { useAuth } from "@/contexts/AuthContext";
import { useStudents } from "@/hooks/useStudents";
import { useRooms } from "@/hooks/useRooms";
import toast from "react-hot-toast";

const BedItem = ({ occupied, onClick, disabled = false }) => (
  <button 
    onClick={onClick} 
    disabled={disabled || occupied}
    className={`relative p-5 rounded-2xl border transition-all duration-300 ${
      occupied
        ? 'bg-indigo-50 border-indigo-100 text-indigo-600 shadow-sm'
        : disabled
          ? 'bg-slate-50 border-slate-100 text-slate-200 cursor-not-allowed opacity-30'
          : 'bg-white border-slate-200 text-slate-400 hover:border-indigo-500 hover:text-indigo-600 hover:shadow-xl active:scale-90'
    }`}
  >
    <Bed size={26} strokeWidth={occupied ? 2.5 : 1.5} />
    {occupied && (
      <div className="absolute top-2 right-2 w-2.5 h-2.5 bg-indigo-600 rounded-full border-2 border-white shadow-sm" />
    )}
  </button>
);

const SkeletonRow = () => (
  <tr className="animate-pulse">
    <td className="py-6 pl-10"><div className="flex items-center gap-6"><div className="w-12 h-12 bg-slate-100 rounded-xl" /><div className="space-y-2"><div className="h-5 bg-slate-100 rounded w-32" /><div className="h-4 bg-slate-50 rounded w-24" /></div></div></td>
    <td className="px-6"><div className="h-7 bg-slate-100 rounded-lg w-28" /></td>
    <td className="px-6"><div className="h-7 bg-slate-100 rounded-lg w-24" /></td>
    <td className="py-6 pr-10"><div className="h-10 bg-slate-100 rounded-xl w-28 ml-auto" /></td>
  </tr>
);

export default function AllocationPage() {
  const { activeHostelId, user } = useAuth();
  const [searchQuery, setSearchQuery] = useState("");
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedStudent, setSelectedStudent] = useState(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [filterType, setFilterType] = useState("all"); 

  const { data: studentsData, isLoading: studentsLoading, refetch: refetchStudents } = useStudents({ limit: 1000 });
  const students = studentsData?.students || [];
  const { data: rooms = [], isLoading: roomsLoading, refetch: refetchRooms, isFetching: roomsFetching } = useRooms();

  const handleAllocate = async (roomId) => {
    if (!selectedStudent || isSubmitting) return;
    setIsSubmitting(true);
    const tid = toast.loading(`Allocating unit for ${selectedStudent.name}...`);
    try {
      await axios.post("/api/allocations", { 
        studentId: selectedStudent.id, 
        roomId, 
        adminId: user?.uid || "system"
      });
      toast.success("Allocation successful.", { id: tid });
      setIsModalOpen(false);
      setSelectedStudent(null);
      refetchStudents();
      refetchRooms();
    } catch (error) {
      toast.error(error.response?.data?.error || "Allocation failed.", { id: tid });
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDeallocate = async (studentId, roomId) => {
    if (isSubmitting) return;
    if (!confirm("Permanently deallocate this resident from their unit?")) return;

    setIsSubmitting(true);
    const tid = toast.loading("Processing deallocation...");
    try {
      await axios.delete("/api/allocations", { data: { studentId, roomId } });
      toast.success("Resident deallocated.", { id: tid });
      refetchStudents();
      refetchRooms();
    } catch (error) {
      toast.error(error.response?.data?.error || "Deallocation failed.", { id: tid });
    } finally {
      setIsSubmitting(false);
    }
  };

  const dashboardStats = useMemo(() => ({
    unassigned: students.filter(s => !s.assignedRoomId).length,
    occupancyPct: rooms.length > 0 
      ? Math.round((rooms.reduce((acc, r) => acc + (r.occupants?.length || 0), 0) / rooms.reduce((acc, r) => acc + (r.capacity || 0), 0)) * 100) 
      : 0,
    availableBeds: rooms.reduce((acc, r) => acc + ((r.capacity || 0) - (r.occupants?.length || 0)), 0)
  }), [students, rooms]);

  const filteredItems = useMemo(() => {
    let result = students.filter(s =>
      s.name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      s.enrollmentId?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      s.email?.toLowerCase().includes(searchQuery.toLowerCase())
    );

    if (filterType === "assigned") result = result.filter(s => !!s.assignedRoomId);
    if (filterType === "unassigned") result = result.filter(s => !s.assignedRoomId);

    return result;
  }, [students, searchQuery, filterType]);

  return (
    <div className="min-h-screen bg-slate-50/10 p-4 sm:p-10 selection:bg-indigo-500/30">
      <div className="max-w-[1600px] mx-auto space-y-12">

        {/* Header Section */}
        <div className="flex flex-col lg:flex-row lg:items-end justify-between gap-10 mb-14">
          <div className="space-y-4">
            <div className="inline-flex items-center gap-3 px-5 py-2 bg-indigo-50 border border-indigo-100 rounded-full shadow-sm">
              <Layers size={14} className="text-indigo-600" />
              <span className="text-[10px] font-black uppercase tracking-[0.3em] text-indigo-600 italic">Allocation Grid</span>
            </div>
            <h1 className="text-4xl sm:text-6xl font-black text-slate-900 tracking-tight italic uppercase leading-none">
              Inventory <span className="text-indigo-600">Allocation</span>.
            </h1>
            <p className="text-slate-500 font-bold mt-2 uppercase text-[10px] sm:text-xs tracking-[0.2em] italic opacity-80">Coordinate resident unit assignments and property occupancy states.</p>
          </div>

          <div className="flex flex-wrap gap-6">
            <div className="bg-white p-8 px-10 rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/20 flex items-center gap-6 group hover:-translate-y-2 transition-all duration-500">
              <div className="p-4 bg-indigo-600 text-white rounded-2xl shadow-xl shadow-indigo-100 group-hover:rotate-6 transition-transform">
                <Users size={22} />
              </div>
              <div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1 italic">Pending Allocation</p>
                <p className="text-3xl font-black text-slate-900 italic">{dashboardStats.unassigned}</p>
              </div>
            </div>
            <div className="bg-white p-8 px-10 rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/20 flex items-center gap-6 group hover:-translate-y-2 transition-all duration-500">
              <div className="p-4 bg-emerald-600 text-white rounded-2xl shadow-xl shadow-emerald-100 group-hover:rotate-6 transition-transform">
                <Bed size={22} />
              </div>
              <div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1 italic">Property Occupancy</p>
                <p className="text-3xl font-black text-slate-900 italic">{dashboardStats.occupancyPct}%</p>
              </div>
            </div>
          </div>
        </div>

        {/* Main Content Area */}
        <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden relative">
          <div className="absolute top-0 left-0 w-full h-1 bg-indigo-500/10" />

          {/* Toolbar */}
          <div className="p-10 border-b border-slate-50 flex flex-col xl:flex-row items-center justify-between gap-10 bg-white">
            <div className="relative w-full xl:max-w-xl group">
              <Search className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 group-focus-within:text-indigo-600 transition-colors" />
              <input 
                type="text" 
                placeholder="SEARCH BY RESIDENT NAME, ID OR EMAIL..." 
                value={searchQuery} 
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-16 pr-8 py-5 bg-slate-50 border border-slate-100 rounded-[2rem] text-xs font-black uppercase tracking-widest text-slate-900 focus:outline-none focus:ring-8 focus:ring-indigo-500/5 focus:bg-white transition-all placeholder:text-slate-200 shadow-inner italic" 
              />
            </div>

            <div className="flex items-center gap-6 w-full xl:w-auto overflow-x-auto no-scrollbar">
              <div className="p-2 bg-slate-50 rounded-[2.5rem] flex items-center gap-2.5 shadow-inner border border-slate-100">
                {[
                  { id: "all", label: "Global View" },
                  { id: "unassigned", label: "Pending" },
                  { id: "assigned", label: "Allocated" }
                ].map((btn) => (
                  <button
                    key={btn.id}
                    onClick={() => setFilterType(btn.id)}
                    className={`px-8 py-3.5 rounded-[1.75rem] text-[10px] font-black uppercase tracking-widest transition-all italic ${
                      filterType === btn.id 
                        ? 'bg-white text-indigo-600 shadow-xl border border-slate-100' 
                        : 'text-slate-400 hover:text-slate-600'
                    }`}
                  >
                    {btn.label}
                  </button>
                ))}
              </div>
              <button 
                onClick={() => { refetchStudents(); refetchRooms(); }}
                className={`p-5 bg-slate-50 border border-slate-100 rounded-2xl text-slate-300 hover:text-indigo-600 transition-all shadow-sm ${roomsFetching ? 'animate-spin text-indigo-600' : ''}`}
              >
                <RefreshCw size={22} />
              </button>
            </div>
          </div>

          {/* Table */}
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/20 border-b border-slate-50">
                  <th className="py-6 pl-10 text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] italic">Resident Detail</th>
                  <th className="px-6 py-6 text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] italic">Unit Assignment</th>
                  <th className="px-6 py-6 text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] italic text-center">Allocation State</th>
                  <th className="py-6 pr-10 text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] italic text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {studentsLoading ? (
                  Array.from({ length: 5 }).map((_, i) => <SkeletonRow key={i} />)
                ) : filteredItems.length === 0 ? (
                  <tr>
                    <td colSpan={4} className="py-40 text-center">
                      <div className="flex flex-col items-center gap-8 text-slate-200">
                        <div className="p-10 bg-slate-50 rounded-[3.5rem] shadow-inner border border-slate-100 italic">
                          <Users size={64} className="opacity-20" />
                        </div>
                        <div className="space-y-2">
                           <p className="text-2xl font-black uppercase tracking-[0.3em] italic">No Records Found</p>
                           <p className="text-[11px] font-bold uppercase tracking-widest opacity-60">Adjust filters or refine search parameters.</p>
                        </div>
                      </div>
                    </td>
                  </tr>
                ) : (
                  filteredItems.map(student => {
                    const isAssigned = !!student.assignedRoomId;
                    const room = rooms.find(r => r.id === student.assignedRoomId);
                    return (
                      <tr key={student.id} className="group hover:bg-slate-50/20 transition-all duration-500">
                        <td className="py-7 pl-10">
                          <div className="flex items-center gap-6">
                            <div className="w-12 h-12 rounded-[1rem] bg-indigo-600 flex items-center justify-center text-white font-black text-lg transform transition-all duration-700 group-hover:rotate-6 shadow-2xl shadow-indigo-100 italic">
                              {student.name?.[0]?.toUpperCase()}
                            </div>
                            <div>
                              <p className="text-sm font-black text-slate-900 group-hover:text-indigo-600 transition-colors uppercase italic tracking-tight">{student.name}</p>
                              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest whitespace-nowrap italic">{student.enrollmentId || student.email}</p>
                            </div>
                          </div>
                        </td>
                        <td className="px-6">
                          {isAssigned ? (
                            <div className="flex items-center gap-3 text-slate-700 font-black italic">
                              <div className="p-2 bg-indigo-50 text-indigo-500 rounded-lg">
                                <Home size={16} />
                              </div>
                              <span className="text-[13px] uppercase tracking-tighter">Unit {room?.roomNumber || student.roomNumber || '...'}</span>
                            </div>
                          ) : (
                            <span className="text-[10px] font-black text-slate-200 uppercase tracking-widest italic font-jakarta">Pending Allocation...</span>
                          )}
                        </td>
                        <td className="px-6 text-center">
                          {isAssigned ? (
                            <span className="inline-flex items-center px-4 py-1.5 rounded-xl bg-emerald-50 text-emerald-600 text-[9px] font-black border border-emerald-100 uppercase tracking-widest italic shadow-sm">
                              Allocated
                            </span>
                          ) : (
                            <span className="inline-flex items-center px-4 py-1.5 rounded-xl bg-amber-50 text-amber-600 text-[9px] font-black border border-amber-100 uppercase tracking-widest italic shadow-sm">
                              Pending
                            </span>
                          )}
                        </td>
                        <td className="py-7 pr-10 text-right">
                          {isAssigned ? (
                            <button 
                              onClick={() => handleDeallocate(student.id, student.assignedRoomId)} 
                              disabled={isSubmitting}
                              className="group/btn inline-flex items-center gap-3 text-[11px] font-black text-slate-300 hover:text-rose-600 transition-all px-6 py-3 rounded-2xl hover:bg-rose-50 border border-transparent hover:border-rose-100 italic uppercase"
                            >
                              <ArrowLeftRight size={16} className="group-hover/btn:rotate-180 transition-transform duration-700" /> Deallocate
                            </button>
                          ) : (
                            <button 
                              onClick={() => { setSelectedStudent(student); setIsModalOpen(true); }}
                              className="group/btn inline-flex items-center gap-3 text-[11px] font-black text-white bg-slate-900 hover:bg-indigo-600 transition-all px-8 py-3.5 rounded-2xl shadow-2xl shadow-slate-200 active:scale-95 italic uppercase tracking-widest"
                            >
                              <UserPlus size={16} className="group-hover/btn:scale-110 transition-transform" /> Allocate Unit
                            </button>
                          )}
                        </td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {/* Modern Room Selection Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-500" onClick={() => setIsModalOpen(false)} />
          <div className="relative bg-white rounded-[4rem] shadow-3xl w-full max-w-6xl max-h-[90vh] flex flex-col overflow-hidden animate-in zoom-in-95 slide-in-from-bottom-20 duration-700 border border-white selection:bg-indigo-500/30">
            <div className="p-10 sm:p-14 border-b border-slate-50 flex items-center justify-between bg-white shrink-0 relative overflow-hidden">
               <div className="absolute top-0 left-0 w-full h-1.5 bg-indigo-600" />
               <div className="flex items-center gap-8 relative z-10">
                  <div className="w-20 h-20 rounded-[2rem] bg-slate-900 border border-slate-800 text-white flex items-center justify-center shadow-3xl shadow-slate-200">
                    <Building2 size={32} />
                  </div>
                  <div>
                     <h2 className="text-3xl font-black text-slate-900 italic uppercase leading-none">Allocate Unit</h2>
                     <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest italic mt-2">Finalizing assignment for <span className="text-indigo-600">{selectedStudent?.name}</span></p>
                  </div>
               </div>
               <button onClick={() => setIsModalOpen(false)} className="p-4 bg-slate-50 text-slate-300 hover:text-rose-600 hover:bg-rose-50 rounded-[1.5rem] transition-all border border-transparent hover:border-rose-100 shadow-sm"><X size={24} /></button>
            </div>

            <div className="p-10 sm:p-16 overflow-y-auto flex-1 bg-slate-50/20 custom-scrollbar">
              {roomsLoading ? (
                <div className="flex flex-col items-center py-32 text-slate-200 gap-8">
                  <Loader2 className="w-16 h-16 text-indigo-600 animate-spin opacity-40" />
                  <p className="text-[11px] font-black uppercase tracking-[0.4em] italic">Scanning Property Inventory…</p>
                </div>
              ) : rooms.filter(r => r.status === 'Available' || r.occupants?.length < r.capacity).length === 0 ? (
                <div className="flex flex-col items-center py-40 text-slate-200 gap-10 text-center">
                  <div className="p-12 bg-white rounded-[4rem] shadow-inner border border-slate-100 italic"><Bed size={80} className="opacity-10" /></div>
                  <div className="space-y-4">
                    <p className="text-3xl font-black uppercase tracking-[0.3em] italic">Property at Full Capacity</p>
                    <p className="text-[11px] font-bold uppercase tracking-widest opacity-60">No residential units match current availability criteria.</p>
                  </div>
                </div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
                   {rooms.filter(r => r.status === 'Available' || r.occupants?.length < r.capacity).map((room) => {
                     const count = room.occupants?.length || 0;
                     const isFull = count >= room.capacity;
                     return (
                       <div key={room.id} className={`group/card bg-white rounded-[3rem] border border-slate-100 p-10 transition-all duration-700 relative overflow-hidden ${isFull ? 'opacity-40 grayscale' : 'hover:border-indigo-200 hover:shadow-2xl hover:-translate-y-2'}`}>
                          <div className="flex items-center justify-between mb-10">
                             <div>
                                <span className="text-[9px] font-black text-slate-300 uppercase tracking-[0.3em] block mb-2 italic">Level {room.floor} Segment</span>
                                <h4 className="text-2xl font-black text-slate-900 leading-none italic uppercase">Unit {room.roomNumber}</h4>
                             </div>
                             <div className={`px-5 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest italic shadow-sm ${isFull ? 'bg-rose-50 text-rose-500 border border-rose-100' : 'bg-emerald-50 text-emerald-600 border border-emerald-100'}`}>
                               {isFull ? 'Maxed' : 'Available'}
                             </div>
                          </div>

                          <div className="flex flex-wrap gap-4 mb-10">
                             {Array.from({ length: room.capacity || 0 }).map((_, idx) => (
                               <BedItem key={idx} occupied={idx < count} disabled={isFull} onClick={() => handleAllocate(room.id)} />
                             ))}
                          </div>

                          <div className="flex items-center justify-between pt-8 border-t border-slate-50 relative z-10">
                             <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest italic group-hover/card:text-indigo-600 transition-colors">{count} / {room.capacity} Units Settled</span>
                             <span className="text-xl font-black text-slate-900 italic tabular-nums group-hover/card:scale-110 transition-transform duration-500">₹{room.price}<span className="text-[10px] text-slate-400 ml-1">/MO</span></span>
                          </div>
                          <div className="absolute -bottom-10 -right-10 w-32 h-32 bg-slate-500/5 rounded-full blur-2xl group-hover/card:scale-150 transition-all duration-1000"></div>
                       </div>
                     );
                   })}
                 </div>
              )}
            </div>

            <div className="p-10 sm:p-14 bg-slate-50 border-t border-slate-100 flex flex-col sm:flex-row items-center justify-between gap-6 shrink-0 z-10">
               <div className="flex items-center gap-4 text-slate-400 text-[10px] font-black uppercase tracking-widest italic">
                  <ShieldCheck size={20} className="text-indigo-500 shadow-sm" />
                  Electronic billing record will be synchronized automatically
               </div>
               <button onClick={() => setIsModalOpen(false)}
                 className="px-10 py-4 text-[11px] font-black text-slate-400 hover:text-slate-900 transition-colors uppercase tracking-widest italic border border-transparent hover:border-slate-200 rounded-2xl"
               >
                 Abort Operation
               </button>
            </div>
          </div>
        </div>
      )}

      {isSubmitting && (
        <div className="fixed inset-0 z-[110] bg-white/60 backdrop-blur-md flex items-center justify-center animate-in fade-in duration-500 px-10">
           <div className="bg-slate-900 p-12 rounded-[3.5rem] shadow-3xl text-center space-y-8 min-w-[320px] animate-in zoom-in-95 duration-700">
              <div className="relative w-20 h-20 mx-auto">
                 <div className="absolute inset-0 border-4 border-indigo-600/20 rounded-full"></div>
                 <div className="absolute inset-0 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
              </div>
              <div className="space-y-2">
                 <h4 className="text-xl font-black text-white italic uppercase tracking-widest">Syncing Registers</h4>
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] italic">Updating property and resident markers…</p>
              </div>
           </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useMemo, memo } from "react";
import Link from "next/link";
import {
  Users, Bed, Activity, MessageSquare, UserCheck,
  TrendingUp, Plus, DollarSign, ArrowRight, Wallet, 
  ShieldCheck, Sparkles, Zap, Heart, Target, Bell,
  BarChart3, LayoutDashboard, Database, Layers,
  Fingerprint, Cpu, Globe, Rocket
} from "lucide-react";
import { useAuth } from "@/contexts/AuthContext";
import { useDashboardStats } from "@/hooks/useDashboardStats";
import { useRooms } from "@/hooks/useRooms";

// ─── SKELETON COMPONENTS ──────────────────────────────────────────────────────
const StatCardSkeleton = () => (
  <div className="bg-white p-10 rounded-[2.5rem] animate-pulse space-y-8 border border-slate-100 shadow-sm">
    <div className="flex justify-between items-start">
      <div className="w-16 h-16 bg-slate-50 rounded-[1.5rem]" />
      <div className="w-20 h-8 bg-slate-50 rounded-full" />
    </div>
    <div className="space-y-4">
      <div className="h-12 bg-slate-50 rounded-xl w-3/4" />
      <div className="h-4 bg-slate-50 rounded-lg w-1/2" />
    </div>
  </div>
);

const DashboardSkeleton = () => (
  <div className="space-y-16 animate-in fade-in duration-500 max-w-[1600px] mx-auto p-10">
    <div className="h-[350px] bg-white rounded-[4rem] animate-pulse border border-slate-100 shadow-sm" />
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-10">
      {[1, 2, 3, 4].map(i => <StatCardSkeleton key={i} />)}
    </div>
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
      <div className="lg:col-span-8 h-[500px] bg-white rounded-[4rem] animate-pulse border border-slate-100 shadow-sm" />
      <div className="lg:col-span-4 h-[500px] bg-slate-50 rounded-[4rem] animate-pulse" />
    </div>
  </div>
);

// ─── COMPONENTS ───────────────────────────────────────────────────────────────
const StatCard = memo(({ title, value, icon: Icon, trend, colorClass, delay }) => (
  <div 
    className="bg-white p-10 rounded-[3rem] border border-slate-100 hover:shadow-2xl hover:shadow-indigo-500/10 hover:-translate-y-2 transition-all duration-700 relative overflow-hidden group animate-in slide-in-from-bottom duration-1000"
    style={{ animationDelay: `${delay}ms` }}
  >
    <div className={`absolute -top-10 -right-10 w-40 h-40 blur-[60px] opacity-10 rounded-full transition-all duration-1000 group-hover:scale-150 ${colorClass}`} />

    <div className="flex items-start justify-between mb-10 relative z-10">
      <div className={`w-16 h-16 rounded-[1.5rem] ${colorClass} bg-opacity-10 text-slate-900 border border-slate-50 flex items-center justify-center shadow-lg transform transition-transform duration-700 group-hover:rotate-6`}>
        <Icon size={24} className={colorClass.replace('bg-', 'text-').split(' ')[0]} strokeWidth={2.5} />
      </div>
