  </Link>
));

const DonutChart = memo(({ percent, size = 180, strokeWidth = 14 }) => {
  const radius = (size - strokeWidth) / 2;
  const circumference = 2 * Math.PI * radius;
  const offset = circumference - (percent / 100) * circumference;
  return (
    <div className="relative group" style={{ width: size, height: size }}>
      <div className="absolute inset-0 bg-indigo-600/10 blur-[50px] rounded-full scale-75 group-hover:scale-125 transition-all duration-1000 opacity-0 group-hover:opacity-100" />
      <svg className="transform -rotate-90 relative z-10" width={size} height={size}>
        <circle cx={size / 2} cy={size / 2} r={radius} stroke="#F8FAFC" strokeWidth={strokeWidth} fill="transparent" />
        <circle cx={size / 2} cy={size / 2} r={radius} stroke="#6366f1" strokeWidth={strokeWidth}
          strokeDasharray={circumference} strokeDashoffset={offset}
          strokeLinecap="round" fill="transparent" className="transition-all duration-1000 ease-out shadow-2xl" />
      </svg>
      <div className="absolute inset-0 flex flex-col items-center justify-center relative z-10">
        <span className="text-4xl font-black text-slate-900 leading-none tracking-tighter italic">{percent}%</span>
        <span className="text-[9px] font-black text-slate-400 uppercase mt-3 tracking-[0.2em] italic">Saturation</span>
      </div>
    </div>
  );
});

