export default function JoinRequestsPage() {
  const { activeHostelId } = useAuth();
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState("pending");
  const [search, setSearch] = useState("");
  const [processingId, setProcessingId] = useState(null);
  const [adminNote, setAdminNote] = useState("");
  const [rejectingId, setRejectingId] = useState(null);

  useEffect(() => {
    if (!activeHostelId) return;

    const fetchRequests = async () => {
      setLoading(true);
      try {
        const res = await axios.get(`/api/hostels/join-requests?hostelId=${activeHostelId}`);
        setRequests(res.data || []);
      } catch (err) {
        toast.error("Failed to fetch join requests");
        console.error(err);
      } finally {
        setLoading(false);
      }
    };

    fetchRequests();
  }, [activeHostelId]);

  const handleAction = async (id, action) => {
    const request = requests.find(r => r.id === id);
    if (!request) return;

    setProcessingId(id);
    try {
      await axios.patch(`/api/hostels/join-requests/${id}`, {
        action,
        studentId: request.userId,
        hostelId: request.hostelId,
        adminNote: action === "reject" ? adminNote : "",
      });

      toast.success(`Protocol ${action}ed successfully`);
      setRequests(prev => prev.map(req => req.id === id ? { ...req, status: action === "approve" ? "approved" : "rejected" } : req));
      if (action === "reject") {
        setRejectingId(null);
        setAdminNote("");
      }
    } catch (err) {
      const errorMsg = err.response?.data?.error || `Failed to ${action} request`;
      toast.error(errorMsg);
    } finally {
      setProcessingId(null);
    }
  };

  const filteredRequests = requests.filter(r => {
    if (r.status !== filter) return false;
    if (search && !r.userName?.toLowerCase().includes(search.toLowerCase()) && !r.userEmail?.toLowerCase().includes(search.toLowerCase())) return false;
    return true;
  });

  const pendingCount = requests.filter(r => r.status === "pending").length;

  return (
    <div className="p-4 sm:p-10 space-y-16 max-w-[1600px] mx-auto min-h-screen pb-20 selection:bg-indigo-500/30">

      {/* SaaS Hub Section */}
      <section className="relative overflow-hidden rounded-[4rem] bg-white border border-slate-100 p-10 sm:p-20 lg:p-24 text-slate-900 shadow-sm group">
        <div className="absolute top-0 right-0 w-[800px] h-full bg-indigo-500/5 blur-[120px] rounded-full pointer-events-none group-hover:scale-125 transition-transform duration-[3s]" />

