export default function StudentsPage() {
  const { activeHostelId } = useAuth();
  const [searchQuery, setSearchQuery] = useState("");
  const [filterRoom, setFilterRoom] = useState("all");
  const [filterStatus, setFilterStatus] = useState("all");
  const [page, setPage] = useState(1);
  const limit = 10;

  const { data, isLoading, isFetching, refetch } = useStudents({ 
    searchQuery, roomId: filterRoom, status: filterStatus, page, limit 
  });

  const { data: rooms = [] } = useRooms();

  const students = data?.students || [];
  const total = data?.total || 0;
  const totalPages = Math.ceil(total / limit);

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [currentStudent, setCurrentStudent] = useState(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef(null);

  const [formData, setFormData] = useState({
    name: "",
    email: "",
    phone: "",
    enrollmentId: "",
    room_id: "",
    status: "Active",
    joinedDate: new Date().toISOString().split("T")[0],
    collegeName: "",
    course: "",
    year: "",
    stayDuration: "",
    profileImage: ""
  });

  // Detail View State
  const [selectedStudentId, setSelectedStudentId] = useState(null);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const openAddModal = () => {
    setIsEditing(false);
    setFormData({
      name: "",
      email: "",
      phone: "",
      enrollmentId: "",
      room_id: "",
      status: "Active",
      joinedDate: new Date().toISOString().split("T")[0],
      collegeName: "",
      course: "",
      year: "",
      stayDuration: "",
      profileImage: ""
    });
    setIsModalOpen(true);
  };

  const openEditModal = (student) => {
    setIsEditing(true);
    setCurrentStudent(student);
    setFormData({
      name: student.name || "",
      email: student.email || "",
      phone: student.phone || student.phoneNumber || "",
      enrollmentId: student.enrollmentId || student.enrollment_id || "",
      room_id: student.room_id || student.assignedRoomId || "",
      status: student.status || "Active",
      joinedDate: student.joinedDate ? student.joinedDate.split("T")[0] : 
                 (student.joined_date ? student.joined_date.split("T")[0] : new Date().toISOString().split("T")[0]),
      collegeName: student.collegeName || "",
      course: student.course || "",
      year: student.year || "",
      stayDuration: student.stayDuration || "",
      profileImage: student.profileImage || ""
    });
    // In edit mode, if Room ID is missing but assignedRoomId exists, we normalize it
    if (!formData.room_id && student.assignedRoomId) {
       setFormData(prev => ({ ...prev, room_id: student.assignedRoomId }));
    }
    setIsModalOpen(true);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    const loadingToast = toast.loading(isEditing ? "Updating profile..." : "Registering student...");
    try {
        // ─── TERM END DATE CALCULATION ──────────────────────────────
        let termEndDate = null;
        if (formData.stayDuration && formData.joinedDate) {
           const startDate = new Date(formData.joinedDate);
           const durationStr = formData.stayDuration;
           if (durationStr.includes("Month")) {
              const months = parseInt(durationStr);
              startDate.setMonth(startDate.getMonth() + months);
           } else if (durationStr.includes("Year")) {
              const years = parseInt(durationStr);
              startDate.setFullYear(startDate.getFullYear() + years);
           }
           termEndDate = startDate;
        }

        // Normalize data before sending to API
        const payload = { 
          ...formData, 
          hostelId: activeHostelId,
          enrollmentId: formData.enrollmentId, // Standardized
          enrollment_id: formData.enrollmentId, // Legacy backward sync
          joinedDate: formData.joinedDate,
          termEndDate: termEndDate ? termEndDate.toISOString() : null
        };

       if (isEditing) {
          await axios.put(`/api/students/${currentStudent.id}`, payload);
          toast.success("Student profile updated!", { id: loadingToast });
       } else {
          await axios.post("/api/students", payload);
          toast.success("Registration complete!", { id: loadingToast });
       }
       setIsModalOpen(false);
       refetch();
    } catch (error) {
       toast.error(error.response?.data?.error || "Error saving record.", { id: loadingToast });
    } finally {
       setIsSubmitting(false);
    }
  };

  const handleImageUpload = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (file.size > 2 * 1024 * 1024) return toast.error("File oversized (Limit: 2MB)");

    setIsUploading(true);
    const loadingToast = toast.loading("Processing image...");
    try {
      // Use student ID if editing, otherwise generate a temp ID for registration
      const targetId = isEditing ? currentStudent.id : `new_${Date.now()}`;
      const storageRef = ref(storage, `profile_images/${targetId}`);
      await uploadBytes(storageRef, file);
      const url = await getDownloadURL(storageRef);

      setFormData(prev => ({ ...prev, profileImage: url }));
      toast.success("Profile image staged for sync.", { id: loadingToast });
    } catch (error) {
      console.error("Upload error:", error);
      toast.error("Cloud storage synchronization failed.", { id: loadingToast });
    } finally {
      setIsUploading(false);
    }
  };

  const handleDelete = async (student) => {
    if (!window.confirm(`Are you sure you want to remove ${student.name}? This action cannot be undone.`)) return;
    const loadingToast = toast.loading("Removing record...");
    try {
       await axios.delete(`/api/students/${student.id}`);
       toast.success("Record deleted.", { id: loadingToast });
       refetch();
    } catch (error) {
       toast.error("Failed to delete record.", { id: loadingToast });
    }
  };

  const exportCSV = () => {
    const headers = ["Name", "Email", "Phone", "Enrollment ID", "Room", "Status", "Joined Date"];
    const rows = students.map(s => [
      s.name, s.email, s.phone, s.enrollmentId || "N/A", s.room_number || "Unassigned", s.status, s.joinedDate
    ]);

    let csvContent = "data:text/csv;charset=utf-8," + headers.join(",") + "\n" + rows.map(r => r.join(",")).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `student_directory_${new Date().toISOString().split("T")[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    toast.success("Directory exported to CSV");
