                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Email Protocol</label>
                            <input type="email" name="email" required value={formData.email} onChange={handleInputChange} className="w-full px-5 py-3.5 bg-slate-50 rounded-2xl border border-slate-100 focus:bg-white focus:ring-8 focus:ring-indigo-500/5 text-sm font-medium text-slate-900 outline-none transition-all" placeholder="john@example.com" />
                         </div>
                         <div className="space-y-2">
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Phone Number</label>
                            <input type="text" name="phone" value={formData.phone} onChange={handleInputChange} className="w-full px-5 py-3.5 bg-slate-50 rounded-2xl border border-slate-100 focus:bg-white focus:ring-8 focus:ring-indigo-500/5 text-sm font-medium text-slate-900 outline-none transition-all" placeholder="+91 00000 00000" />
                         </div>
