                            <input type="text" name="enrollmentId" value={formData.enrollmentId} onChange={handleInputChange} className="w-full px-5 py-3.5 bg-slate-50 rounded-2xl border border-slate-100 focus:bg-white focus:ring-8 focus:ring-indigo-500/5 text-sm font-bold text-slate-900 outline-none transition-all uppercase tracking-wider" placeholder="STUD-001" />
                         </div>
                      </div>
                   </div>

                   {/* Academic Section */}
                   <div className="space-y-6">
                      <div className="flex items-center gap-3">
                         <div className="w-8 h-8 rounded-xl bg-orange-50 text-orange-600 flex items-center justify-center"><BookOpen size={14} /></div>
                         <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Academic Background</h4>
                      </div>
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                         <div className="space-y-2">
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">College / Institute</label>
                            <input type="text" name="collegeName" value={formData.collegeName} onChange={handleInputChange} className="w-full px-5 py-3.5 bg-slate-50 rounded-2xl border border-slate-100 focus:bg-white focus:ring-8 focus:ring-indigo-500/5 text-sm font-medium text-slate-900 outline-none transition-all" placeholder="e.g. LDRP-ITR" />
                         </div>
                         <div className="flex gap-4">
