                               <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Course</label>
                               <input type="text" name="course" value={formData.course} onChange={handleInputChange} className="w-full px-5 py-3.5 bg-slate-50 rounded-2xl border border-slate-100 focus:bg-white focus:ring-8 focus:ring-indigo-500/5 text-sm font-medium text-slate-900 outline-none transition-all" placeholder="B.Tech" />
                            </div>
