                               <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Year</label>
                               <input type="text" name="year" value={formData.year} onChange={handleInputChange} className="w-full px-5 py-3.5 bg-slate-50 rounded-2xl border border-slate-100 focus:bg-white focus:ring-8 focus:ring-indigo-500/5 text-sm font-medium text-slate-900 outline-none transition-all" placeholder="3rd" />
                            </div>
                         </div>
                      </div>
                   </div>

                   {/* Allocation & Duration Section */}
                   <div className="space-y-6">
                      <div className="flex items-center gap-3">
                         <div className="w-8 h-8 rounded-xl bg-emerald-50 text-emerald-600 flex items-center justify-center"><Calendar size={14} /></div>
                         <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Stay Preferences</h4>
                      </div>
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                         <div className="space-y-2">
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Join Date</label>
                            <input type="date" name="joinedDate" value={formData.joinedDate} onChange={handleInputChange} className="w-full px-5 py-3.5 bg-slate-50 rounded-2xl border border-slate-100 focus:bg-white focus:ring-8 focus:ring-indigo-500/5 text-sm font-medium text-slate-900 outline-none transition-all" />
                         </div>
                         <div className="space-y-2">
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Stay Duration</label>
                            <select name="stayDuration" value={formData.stayDuration} onChange={handleInputChange} className="w-full px-5 py-3.5 bg-slate-50 rounded-2xl border border-slate-100 focus:bg-white focus:ring-8 focus:ring-indigo-500/5 text-sm font-bold text-slate-900 outline-none transition-all cursor-pointer">
                               <option value="">Select Duration</option>
                               <option value="6 Months">6 Months</option>
                               <option value="1 Year">1 Year</option>
                               <option value="2 Years">2 Years</option>
                               <option value="3 Years">3 Years</option>
                               <option value="4 Years">4 Years</option>
                            </select>
                         </div>
                         <div className="space-y-2">
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Room Allocation</label>
                            <select name="room_id" value={formData.room_id} onChange={handleInputChange} className="w-full px-5 py-3.5 bg-slate-50 rounded-2xl border border-slate-100 focus:bg-white focus:ring-8 focus:ring-indigo-500/5 text-sm font-bold text-slate-900 outline-none transition-all cursor-pointer">
                               <option value="">Unassigned</option>
                               {rooms.map(r => <option key={r.id} value={r.id}>Room {r.room_number?.toString()} ({r.status})</option>)}
                            </select>
                         </div>
                         <div className="space-y-2">
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Resident Status</label>
                            <div className="flex bg-slate-100 p-1 rounded-xl border border-slate-100">
                               {['Active', 'Inactive'].map((s) => (
                                 <button key={s} type="button" onClick={() => setFormData(p => ({ ...p, status: s }))} className={`flex-1 py-2 text-[10px] font-bold uppercase tracking-wider rounded-lg transition-all ${formData.status === s ? 'bg-white text-indigo-600 shadow-sm border border-slate-200/20' : 'text-slate-400 hover:text-slate-600'}`}> {s} </button>
                               ))}
                            </div>
                         </div>
                      </div>
                   </div>

                  <div className="pt-10 border-t border-slate-50 flex items-center gap-6">
                     <button
                        type="submit"
                        disabled={isSubmitting}
                        className="flex-1 flex items-center justify-center gap-3 rounded-2xl bg-slate-900 px-8 py-5 text-xs font-bold text-white uppercase tracking-widest shadow-2xl hover:bg-indigo-600 transition-all active:scale-95 disabled:opacity-50"
                     >
                        {isSubmitting ? <Loader2 className="w-5 h-5 animate-spin" /> : <Save size={18} />}
                        {isEditing ? "Save Changes" : "Register Resident"}
                     </button>
                     <button
                        type="button"
                        onClick={() => setIsModalOpen(false)}
                        className="px-8 py-5 bg-slate-50 text-slate-400 font-bold uppercase tracking-widest text-xs rounded-2xl hover:bg-rose-50 hover:text-rose-500 transition-all border border-slate-100 active:scale-95"
                     > Cancel </button>
                  </div>
               </form>
            </div>
         </div>
      )}
    </div>
  );
}

"use client";

import { useState, useMemo } from "react";
import axios from "axios";
import { 
  Loader2, Search, UserCheck, Clock, LogIn, 
  Plus, X, Users, AlertTriangle, History, ArrowRight, User, Trash2, Edit3,
  Calendar, MapPin, Sparkles, RefreshCw, ShieldCheck, ShieldAlert
} from "lucide-react";
import { useAuth } from "@/contexts/AuthContext";
import { useVisitors, useVisitorRequests } from "@/hooks/useVisitors";
import StudentPicker from "@/components/StudentPicker";
import toast from "react-hot-toast";

const StatCard = ({ label, val, icon: Icon, colorClass, description }) => (
  <div className="bg-white p-7 rounded-[2rem] border border-slate-200/60 shadow-sm flex items-center justify-between group transition-all hover:shadow-xl hover:-translate-y-1">
    <div className="space-y-2">
      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{label}</p>
      <p className="text-4xl font-extrabold text-slate-900 tracking-tight">{val}</p>
      <p className="text-[10px] font-medium text-slate-400">{description}</p>
    </div>
    <div className={`w-16 h-16 rounded-2xl ${colorClass} bg-opacity-10 flex items-center justify-center shadow-inner transition-transform group-hover:rotate-6`}>
      <Icon size={28} className={colorClass.replace('bg-', 'text-')} />
    </div>
  </div>
);

export default function AdministrativeVisitorsPage() {
  const { activeHostelId, role } = useAuth();
  const [activeTab, setActiveTab] = useState("active_log"); 
  const [searchQuery, setSearchQuery] = useState("");
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [showRejectModal, setShowRejectModal] = useState(null);
  const [rejectReason, setRejectReason] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [form, setForm] = useState({ 
    name: "", purpose: "", studentId: "", studentName: "", roomNo: "", phone: "", type: "Personal"
  });

  const { data: visitors = [], isLoading, isFetching, refetch } = useVisitors();
  const { data: requests = [], isLoading: requestsLoading, refetch: refetchRequests } = useVisitorRequests();

  const isAdmin = role === "admin";

  const handleApprove = async (req) => {
    if (!isAdmin) return toast.error("Administrative privileges required.");
    const tid = toast.loading(`Authorizing visit for ${req.visitorName}...`);
    try {
      await axios.put("/api/visitors/admin/requests", {
        requestId: req.id,
        status: "approved",
        adminNote: "Visit authorized by administration.",
        visitorData: {
          name: req.visitorName, phone: req.visitorPhone, hostStudentId: req.studentId,
          studentName: req.studentName, roomNo: req.roomNo, purpose: req.purpose,
          hostelId: activeHostelId
        },
        hostelId: activeHostelId
      });
      toast.success(`Access granted for ${req.visitorName}`, { id: tid });
      refetchRequests();
      refetch();
    } catch (err) {
      toast.error("Failed to approve visit request.", { id: tid });
    }
  };

  const handleReject = async (requestId) => {
    if (!isAdmin) return toast.error("Unauthorized.");
    if (!rejectReason) return toast.error("Please provide a justification for dismissal.");
    const tid = toast.loading("Dismissing request...");
    try {
      await axios.put("/api/visitors/admin/requests", {
        requestId, status: "rejected", adminNote: rejectReason, hostelId: activeHostelId
      });
      toast.success("Request dismissed successfully.", { id: tid });
      setShowRejectModal(null);
      setRejectReason("");
      refetchRequests();
    } catch (err) {
      toast.error("Process failed.", { id: tid });
    }
  };

  const handleCheckIn = async (e) => {
    e.preventDefault();
    if (!isAdmin) return toast.error("Unauthorized.");
    if (!form.name || !form.purpose || !form.studentId) {
      return toast.error("Please complete all required fields.");
    }

    setIsSubmitting(true);
    const tid = toast.loading(editingId ? "Updating profile..." : "Processing check-in...");
    try {
      if (editingId) {
        await axios.put(`/api/visitors/${editingId}`, {
          ...form, hostStudentId: form.studentId, hostelId: activeHostelId
        });
        toast.success("Profile updated", { id: tid });
      } else {
        await axios.post("/api/visitors", {
          ...form, hostStudentId: form.studentId, hostelId: activeHostelId
        });
        toast.success(`${form.name} checked in successfully.`, { id: tid });
      }

      resetForm();
      refetch();
    } catch (err) {
      toast.error("Entry process failed.", { id: tid });
    } finally {
      setIsSubmitting(false);
    }
  };

  const resetForm = () => {
    setForm({ name: "", purpose: "", studentId: "", studentName: "", roomNo: "", phone: "", type: "Personal" });
    setShowForm(false);
    setEditingId(null);
  };

  const handleEdit = (v) => {
    setForm({
      name: v.name || "", purpose: v.purpose || "", studentId: v.hostStudentId || "",
      studentName: v.studentName || "", roomNo: v.roomNo || "", phone: v.phone || "", type: v.type || "Personal"
    });
    setEditingId(v.id);
    setShowForm(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleDelete = async (id) => {
    if (!isAdmin) return toast.error("Unauthorized.");
    if (!confirm("Permanently delete this visitor record? This action cannot be undone.")) return;
    const tid = toast.loading("Deleting record...");
    try {
      await axios.delete(`/api/visitors/${id}`);
      toast.success("Record deleted", { id: tid });
      refetch();
    } catch (err) {
      toast.error("Cleanup failed.", { id: tid });
    }
  };

  const handleCheckOut = async (visitorId) => {
    if (!isAdmin) return toast.error("Unauthorized.");
    const tid = toast.loading("Processing check-out...");
    try {
      await axios.put(`/api/visitors/${visitorId}`, { status: "Departed", hostelId: activeHostelId });
      toast.success("Check-out completed.", { id: tid });
      refetch();
    } catch (err) {
      toast.error("Check-out failed.", { id: tid });
    }
  };

  const handleCheckInArrival = async (visitorId) => {
    if (!isAdmin) return toast.error("Unauthorized.");
    const tid = toast.loading("Verifying arrival...");
    try {
      await axios.put(`/api/visitors/${visitorId}`, {
        status: "Present", checkIn: new Date().toISOString(), hostelId: activeHostelId
      });
      toast.success("Arrival verified.", { id: tid });
      refetch();
    } catch (err) {
      toast.error("Verification failed.", { id: tid });
    }
  };

  const getDuration = (start, end) => {
    if (!start) return "N/A";
    const s = new Date(start);
    const e = end ? new Date(end) : new Date();
    const diff = Math.abs(e - s);
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const mins = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
    return `${hours}h ${mins}m`;
  };

  const isOverstay = (checkIn, checkOut) => {
    if (checkOut) return false;
    if (!checkIn) return false;
    const diff = Math.abs(new Date() - new Date(checkIn));
    return diff > (1000 * 60 * 60 * 4); // 4 hours
  };

  const filteredVisitors = useMemo(() => {
    return (visitors || []).filter(v =>
      v.name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      v.studentName?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      v.purpose?.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [visitors, searchQuery]);

  const stats = useMemo(() => {
    const list = visitors || [];
    const active = list.filter(v => !v.checkOut && v.status === "Present");
    const overstays = active.filter(v => isOverstay(v.checkIn, null));
    return {
      total: list.length,
      inside: active.length,
      overstays: overstays.length
    };
  }, [visitors]);

  if (!isAdmin) {
    return (
      <div className="min-h-screen flex items-center justify-center p-8 bg-slate-50">
        <div className="bg-white p-12 rounded-[3.5rem] border border-slate-200 shadow-2xl max-w-xl text-center space-y-8 animate-in zoom-in duration-500">
           <div className="w-24 h-24 bg-rose-50 rounded-full flex items-center justify-center mx-auto text-rose-500 shadow-inner">
             <ShieldAlert size={48} />
           </div>
           <div className="space-y-4">
             <h2 className="text-3xl font-black text-slate-900 tracking-tight">Access Restricted</h2>
             <p className="text-slate-500 font-medium leading-relaxed">Visitor management functions are restricted to administrative personnel. Please contact the security head for authorization.</p>
           </div>
           <button onClick={() => window.history.back()} className="px-10 py-5 bg-slate-900 text-white font-bold rounded-[2rem] hover:bg-slate-800 transition-all shadow-xl active:scale-95">Go Back</button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50/20 p-4 sm:p-10 space-y-12 max-w-7xl mx-auto pb-32">

      {/* Header Section */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-10">
        <div className="space-y-4">
          <div className="inline-flex items-center gap-3 px-5 py-2 bg-indigo-50 border border-indigo-100 rounded-full shadow-sm">
             <Sparkles size={14} className="text-indigo-600" />
             <span className="text-[10px] font-bold uppercase tracking-[0.2em] text-indigo-700">Access Management</span>
          </div>
          <h1 className="text-5xl lg:text-6xl font-black text-slate-900 tracking-tight leading-none uppercase italic">Visitors.</h1>
          <p className="text-slate-500 font-medium text-lg leading-relaxed max-w-2xl">Monitor real-time guest arrivals and manage pre-authorized visit requests.</p>
        </div>

        <div className="flex flex-col sm:flex-row items-center gap-4 bg-white p-2 rounded-[2.5rem] border border-slate-200/60 shadow-sm">
           <button 
             onClick={() => setActiveTab("active_log")}
             className={`px-8 py-4 rounded-[2rem] text-[10px] font-bold uppercase tracking-widest transition-all ${
               activeTab === "active_log" ? "bg-slate-900 text-white shadow-xl" : "text-slate-400 hover:text-slate-600 hover:bg-slate-50"
             }`}
           >
             Security Log
           </button>
           <button 
             onClick={() => setActiveTab("visit_requests")}
             className={`relative px-8 py-4 rounded-[2rem] text-[10px] font-bold uppercase tracking-widest transition-all ${
               activeTab === "visit_requests" ? "bg-slate-900 text-white shadow-xl" : "text-slate-400 hover:text-slate-600 hover:bg-slate-50"
             }`}
           >
             Visit Requests
             {requests.length > 0 && (
               <div className="absolute -top-1 -right-1 w-6 h-6 bg-rose-500 text-white text-[10px] rounded-full flex items-center justify-center font-black border-2 border-white animate-bounce">
                 {requests.length}
               </div>
             )}
           </button>
        </div>
      </div>

      {activeTab === "active_log" ? (
        <>
          {/* Key Metrics */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
            <StatCard label="Total Admissions" val={stats.total} icon={Users} colorClass="bg-indigo-500" description="Total visitors logged since inception" />
            <StatCard label="On-Site Presence" val={stats.inside} icon={LogIn} colorClass="bg-emerald-500" description="Verified guests currently on premises" />
            <StatCard label="Security Alerts" val={stats.overstays} icon={AlertTriangle} colorClass={stats.overstays > 0 ? "bg-rose-500" : "bg-slate-500"} description="Beyond 4-hour standard duration" />
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-12 gap-10 items-start">
            {/* Control Panel */}
            <div className="lg:col-span-4 space-y-10">
              <div className="bg-white rounded-[3rem] border border-slate-200/60 p-10 space-y-10 shadow-sm relative overflow-hidden group">
                <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500 opacity-[0.03] blur-3xl group-hover:opacity-10 transition-opacity"></div>

                <div className="flex items-center gap-6">
                  <div className="w-14 h-14 rounded-2xl bg-indigo-600 text-white flex items-center justify-center shadow-xl shadow-indigo-100 transition-transform group-hover:scale-110">
                    <UserCheck size={24} />
                  </div>
                  <div>
                     <h3 className="text-xl font-bold text-slate-900">{editingId ? "Modify Entry" : "Register Visit"}</h3>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Manual Data Entry</p>
                  </div>
                </div>

                <form onSubmit={handleCheckIn} className="space-y-8">
                  <div className="space-y-2">
                    <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-1">Visitor Identity</label>
                    <div className="relative">
                      <User className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                      <input
                        type="text"
                        required
                        placeholder="Full Legal Name"
                        value={form.name}
                        onChange={(e) => setForm({ ...form, name: e.target.value })}
                        className="premium-input !pl-14"
                      />
                    </div>
                  </div>

                  <div className="space-y-2">
