            Sign in to continue to your dashboard
          </p>
        </div>

        {/* Role Selector */}
        <SaaSRoleToggle role={role} setRole={setRole} />

        <form onSubmit={handleSubmit(onSubmit)} className="space-y-5">
          <SaaSInput 
            label="Email Address"
            id="email"
            type="email"
            placeholder="you@example.com"
            register={register("email")}
