"use client";

import { useEffect, useState, useMemo, useCallback } from "react";
import axios from "axios";
import { useAuth } from "@/contexts/AuthContext";
import { 
  Loader2, Search, CreditCard, Calendar, CheckCircle, AlertTriangle, 
  Clock, ArrowRight, X, ShieldCheck, Smartphone, Building2, History, Receipt,
  Wallet, DollarSign, ArrowLeft, RefreshCw, AlertCircle, Download
} from "lucide-react";
import toast from "react-hot-toast";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";

const MONTHS = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];

const generateReceipt = (payment, user, fee, hostelData) => {
  const doc = new jsPDF();
  const hostelName = hostelData?.name || "HostelHub";

  // Brand Header
  doc.setFillColor(79, 70, 229); // Indigo 600
  doc.rect(0, 0, 210, 40, 'F');

  doc.setTextColor(255, 255, 255);
  doc.setFontSize(22);
  doc.setFont("helvetica", "bold");
  doc.text(hostelName, 14, 25);

  doc.setFontSize(10);
  doc.setFont("helvetica", "normal");
  doc.text("Payment Receipt", 160, 25);

  // Content
  doc.setTextColor(30, 41, 59); // Slate 900
  doc.setFontSize(12);
  doc.setFont("helvetica", "bold");
  doc.text("Transaction Details", 14, 60);

  const txnId = payment?.id || payment?.transactionId || `TXN-${Math.random().toString(36).substring(2, 10).toUpperCase()}`;
  const date = new Date(payment?.timestamp || payment?.paidAt || Date.now()).toLocaleDateString();
  const amount = payment?.amount || fee?.amount || 0;

  // Billing Period Logic
  let periodStr = "N/A";
  if (payment?.billingPeriod?.start && payment?.billingPeriod?.end) {
     const start = new Date(payment.billingPeriod.start.seconds * 1000).toLocaleDateString();
     const end = new Date(payment.billingPeriod.end.seconds * 1000).toLocaleDateString();
     periodStr = `${start} - ${end}`;
  } else if (fee?.month) {
     periodStr = `${MONTHS[fee.month-1]} ${fee.year}`;
  }

  const method = payment?.method || payment?.paymentMethod || "Online";

  autoTable(doc, {
    startY: 70,
    head: [['Description', 'Details']],
    body: [
      ['Transaction ID', txnId],
      ['Date', date],
      ['Resident Name', user?.name || user?.displayName || "N/A"],
      ['Resident Email', user?.email || "N/A"],
      ['Billing Period / Coverage', periodStr],
      ['Payment Method', method],
      ['Status', 'Paid Successfully'],
    ],
    theme: 'grid',
    headStyles: { fillColor: [241, 245, 249], textColor: [71, 85, 105] },
    styles: { fontSize: 10, cellPadding: 6 },
    columnStyles: { 0: { fontStyle: 'bold', cellWidth: 50 } }
  });

  // Total
  const finalY = (doc).lastAutoTable.finalY + 20;
  doc.setFontSize(14);
  doc.setFont("helvetica", "bold");
  doc.text(`Total Paid: $${amount.toLocaleString()}`, 14, finalY);

  // Footer
  doc.setFontSize(8);
  doc.setFont("helvetica", "normal");
  doc.setTextColor(148, 163, 184); // slate-400
  doc.text("This is an electronically generated document. No signature required.", 14, 280);

  doc.save(`Receipt_${txnId}.pdf`);
};

const PaymentModal = ({ fee, user, hostelData, onClose, onPaymentSuccess }) => {
  const [method, setMethod] = useState(null);
  const [duration, setDuration] = useState(1);
  const [processing, setProcessing] = useState(false);
  const [step, setStep] = useState(1);

  const handleProcess = async () => {
    if (!method) return;
    setProcessing(true);
    setStep(2);
    const tid = toast.loading("Finalizing your payment...");
    try {
      await new Promise(resolve => setTimeout(resolve, 1500));
      const res = await axios.post("/api/pay", { 
        feeId: fee.id, 
        studentId: user.uid, 
        studentName: user.name || user.email, 
        amount: fee.amount, 
        method,
        durationMonths: duration
      });
      if (res.data.success) {
        toast.success("Payment successful! Official receipt generated.", { id: tid });
        // Generate receipt locally with the new data
        generateReceipt({ 
          method, 
          amount: fee.amount,
          transactionId: res.data.transactionId || res.data.reference
        }, user, fee, hostelData);
        onPaymentSuccess();
        onClose();
      }
    } catch (error) {
      toast.error(error.response?.data?.error || "Transaction failed. Please try again.", { id: tid });
      setStep(1);
    } finally {
      setProcessing(false);
    }
  };

  if (!fee) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={onClose} />
      <div className="relative bg-white w-full max-w-lg rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in duration-200">

        {/* Header */}
        <div className="p-8 border-b border-slate-100 flex items-center justify-between">
           <div className="flex items-center gap-4">
              <div className="w-12 h-12 rounded-2xl bg-indigo-600 text-white flex items-center justify-center shadow-lg shadow-indigo-100">
                <ShieldCheck size={24} />
              </div>
              <div>
                 <h2 className="text-xl font-bold text-slate-900">Checkout</h2>
                 <p className="text-xs font-medium text-slate-500">Secure payment portal</p>
              </div>
           </div>
           <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full text-slate-400 transition-colors">
             <X size={20} />
           </button>
        </div>

        <div className="p-8 space-y-8">
          {step === 1 ? (
            <div className="space-y-8">
              <div className="bg-slate-50 rounded-2xl p-6 border border-slate-100 flex items-center justify-between">
                <div>
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Total Amount</p>
                  <h3 className="text-3xl font-bold text-slate-900">${(fee.amount * duration).toLocaleString()}</h3>
                </div>
                <div className="text-right">
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">Billing Period</p>
                  <p className="text-sm font-bold text-slate-900">{MONTHS[fee.month-1]} {fee.year}</p>
                </div>
              </div>

               <div className="space-y-3">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider ml-1">Fee Coverage</label>
                <div className="grid grid-cols-4 gap-2">
                   {[
                     { label: '1 mo', value: 1 },
                     { label: '3 mo', value: 3 },
                     { label: '6 mo', value: 6 },
                     { label: '1 yr', value: 12 }
                   ].map(opt => (
                     <button
                        key={opt.value}
                        onClick={() => setDuration(opt.value)}
                        className={`py-2.5 rounded-xl border-2 text-[10px] font-black uppercase tracking-widest transition-all ${
                          duration === opt.value ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white border-slate-100 text-slate-400 hover:border-slate-200'
                        }`}
                     >
                        {opt.label}
                     </button>
                   ))}
                </div>
              </div>

              <div className="space-y-3">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider ml-1">Payment Method</label>
                <div className="grid grid-cols-2 gap-4">
                  <button 
                    onClick={() => setMethod('UPI')}
                    className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center gap-3 ${
                      method === 'UPI' ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-100 hover:border-indigo-100 bg-white text-slate-400'
                    }`}
                  >
                    <Smartphone size={24} />
                    <span className="text-xs font-bold">UPI</span>
                  </button>
                  <button 
                    onClick={() => setMethod('Card')}
                    className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center gap-3 ${
                      method === 'Card' ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-100 hover:border-indigo-100 bg-white text-slate-400'
                    }`}
                  >
                    <CreditCard size={24} />
                    <span className="text-xs font-bold">Card</span>
                  </button>
                </div>
              </div>

              <button 
                disabled={!method || processing} 
                onClick={handleProcess}
                className="w-full py-4 bg-slate-900 text-white rounded-xl font-bold text-sm shadow-xl hover:bg-slate-800 transition-all active:scale-95 disabled:opacity-30 flex items-center justify-center gap-3"
              >
                {processing ? <Loader2 size={18} className="animate-spin" /> : <Wallet size={18} />}
                Pay Now
              </button>
            </div>
          ) : (
            <div className="py-12 flex flex-col items-center text-center gap-6">
              <div className="w-20 h-20 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
              <div>
                <h4 className="text-lg font-bold text-slate-900 uppercase">Processing Payment</h4>
