                <Skeleton className="h-16 sm:h-20 rounded-[1.5rem] sm:rounded-[2rem]" />
              </div>
            </div>
            <Skeleton className="h-48 sm:h-64 rounded-[2.5rem] sm:rounded-[3rem]" />
