  const statusTags = {
    pending: "Pending Review",
    approved: "Approved",
    rejected: "Request Declined",
    Departed: "Checked Out",
    Inside: "On-site",
  };

  const status = isHistory ? request.status : request.status;

  return (
    <div 
      className="p-7 rounded-[2rem] bg-white border border-slate-200/60 shadow-sm hover:shadow-2xl transition-all duration-500 group relative overflow-hidden animate-slide-up"
