      <div className={`absolute top-0 right-0 w-32 h-32 blur-[60px] opacity-10 rounded-full -mr-10 -mt-10 transition-all duration-700 group-hover:scale-150 ${statusColors[status]?.split(' ')[0] || 'bg-slate-500'}`} />

