              {request.visitorName?.charAt(0) || request.name?.charAt(0)}
            </div>
            <div>
              <h3 className="text-sm font-bold text-slate-900 tracking-tight uppercase">{request.visitorName || request.name}</h3>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{request.relation || request.type || 'Visitor'}</p>
            </div>
          </div>
          <div className={`px-4 py-1.5 rounded-full ${statusColors[status]?.split(' ')[0] || 'bg-slate-500'} bg-opacity-10 border border-current text-[9px] font-bold uppercase tracking-widest flex items-center gap-2`}>
            <div className={`w-1.5 h-1.5 rounded-full ${statusColors[status]?.split(' ')[0]?.replace('bg-', 'text-') || 'text-slate-500'} animate-pulse`} />
            {statusTags[status] || status}
