        </div>

        <div className="grid grid-cols-2 gap-4 mb-8">
          <div className="space-y-1.5 p-3 rounded-2xl bg-slate-50/50 border border-slate-100 transition-colors group-hover:bg-white group-hover:shadow-sm">
