          </div>
          <div className="space-y-1.5 p-3 rounded-2xl bg-slate-50/50 border border-slate-100 transition-colors group-hover:bg-white group-hover:shadow-sm">
             <div className="flex items-center gap-2 text-[9px] font-bold text-slate-400 uppercase tracking-widest">
               <User size={12} className="text-indigo-500" /> Purpose
             </div>
             <p className="text-xs font-bold text-slate-900 leading-none truncate">{request.purpose}</p>
          </div>
        </div>

        {request.adminNote && (
          <div className="mb-8 p-4 rounded-2xl bg-rose-50 border border-rose-100 text-rose-600 text-[10px] font-bold flex items-start gap-3">
             <MessageSquare size={14} className="shrink-0 mt-0.5" />
