              <div className="p-2 rounded-xl bg-indigo-50 text-indigo-600"><Phone size={14} /></div>
              <span className="text-[11px] font-bold text-slate-500 font-mono italic">{request.visitorPhone || request.phone}</span>
           </div>
           {request.status === "pending" && (
             <button 
               onClick={() => onCancel(request.id)}
