      </div>
    </div>
  );
};

export default function StudentVisitorsPage() {
  const { user, userData } = useAuth();
  const { addToast } = useToast();
  const [requests, setRequests] = useState([]);
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState("pending");
  const [showModal, setShowModal] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [form, setForm] = useState({
    visitorName: "",
    visitorPhone: "",
    relation: "Parent",
    visitDate: "",
    visitTime: "9AM - 12PM",
    duration: "1 hour",
    purpose: "Personal",
    notes: ""
  });

  const fetchData = async () => {
    if (!user?.uid || !userData?.hostelId) return;
    setLoading(true);
    try {
      const [reqsRes, histRes] = await Promise.all([
        axios.get(`/api/visitors/request?studentId=${user.uid}&hostelId=${userData.hostelId}`),
        axios.get(`/api/visitors?hostStudentId=${user.uid}&hostelId=${userData.hostelId}`)
      ]);
      setRequests(reqsRes.data);
      setHistory(histRes.data);
    } catch (err) {
      console.error("Failed to fetch data:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, [user, userData]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.visitorName || !form.visitDate || !form.visitorPhone) {
      addToast("Please fill in all required fields.", "warning");
      return;
    }

    setIsSubmitting(true);
    try {
      await axios.post("/api/visitors/request", {
        ...form,
        studentId: user.uid,
        studentName: userData?.name || "Verified Resident",
        roomNo: userData?.roomNumber || "N/A",
        hostelId: userData?.hostelId
      });
      addToast("Visitor request submitted for approval.", "success");
      setShowModal(false);
      setForm({ visitorName: "", visitorPhone: "", relation: "Parent", visitDate: "", visitTime: "9AM - 12PM", duration: "1 hour", purpose: "Personal", notes: "" });
      fetchData();
    } catch (err) {
      addToast("Failed to submit request.", "error");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleCancel = async (id) => {
    if (!confirm("Are you sure you want to cancel this request?")) return;
    try {
      // In a real app we'd have a specific cancel API
      await axios.delete(`/api/visitors/request?id=${id}`); // placeholder
      addToast("Request cancelled successfully.", "success");
      setRequests(prev => prev.filter(r => r.id !== id));
    } catch (err) {
      addToast("Failed to cancel request.", "error");
    }
  };

  const getFilteredContent = () => {
    if (activeTab === "past") return history;
    if (activeTab === "all") return [...requests, ...history];
    return requests.filter(r => r.status === activeTab);
  };

  const filteredContent = getFilteredContent();

  if (loading && requests.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-48 text-slate-400 gap-6">
        <div className="relative">
           <div className="w-16 h-16 border-4 border-indigo-500/10 border-t-indigo-500 rounded-full animate-spin" />
           <Users className="absolute inset-0 m-auto text-indigo-500 animate-pulse" size={20} />
        </div>
        <p className="font-bold uppercase tracking-widest text-[10px] animate-pulse">Loading Visitor Records...</p>
      </div>
    );
  }

  return (
    <div className="space-y-12 pb-20 max-w-7xl mx-auto p-4 md:p-0">

      {/* SaaS Platinum Header */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-8 relative overflow-hidden p-12 rounded-[3.5rem] bg-white border border-slate-200/60 shadow-xl">
        <div className="absolute top-0 right-0 w-96 h-full bg-indigo-500/5 blur-[100px] rounded-full pointer-events-none" />

        <div className="max-w-2xl space-y-6 relative z-10">
          <div className="inline-flex items-center gap-3 px-5 py-2 bg-indigo-50 border border-indigo-100 rounded-full shadow-sm">
             <Sparkles size={14} className="text-indigo-500" />
