"use client";

import { useState, useEffect } from "react";
import toast from "react-hot-toast";
import axios from "axios";
import { Settings, Key, RotateCw } from "lucide-react";

export default function HostelSettingsPanel({ hostelId, hostelName: initialName }) {
  const [settings, setSettings] = useState({
    hostelName: "",
    autoApprove: false,
    joinCode: "",
  });
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    if (hostelId) {
      fetchSettings();
    }
  }, [hostelId]);

  const fetchSettings = async () => {
    setLoading(true);
    try {
      const response = await axios.get(`/api/hostels/${hostelId}/settings`);
      setSettings({
        hostelName: response.data.hostel?.hostelName || "",
        autoApprove: response.data.hostel?.autoApprove || false,
        joinCode: response.data.hostel?.joinCode || "",
      });
    } catch (error) {
      console.error("Fetch error:", error);
      toast.error("Failed to load settings");
    } finally {
      setLoading(false);
    }
  };

  const handleSaveSettings = async () => {
    setSaving(true);
    try {
      await axios.patch(`/api/hostels/${hostelId}/settings`, {
        autoApprove: settings.autoApprove,
      });
      toast.success("Settings updated successfully!");
    } catch (error) {
      console.error("Save error:", error);
      toast.error("Failed to save settings");
    } finally {
      setSaving(false);
    }
  };

  const handleRegenerateCode = async () => {
    if (!window.confirm("Are you sure? Students using the old code won't be able to join.")) {
      return;
    }

    try {
      const response = await axios.post(`/api/hostels/${hostelId}/regenerate-code`);
      setSettings((prev) => ({
        ...prev,
        joinCode: response.data.joinCode,
      }));
      toast.success("Join code regenerated!");
    } catch (error) {
      console.error("Regenerate error:", error);
      toast.error("Failed to regenerate code");
    }
  };

  if (loading) {
    return (
      <div className="bg-white rounded-lg shadow p-6">
        <div className="text-center py-8 text-gray-500">Loading...</div>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-lg shadow p-6 space-y-6">
      <div>
        <h2 className="text-2xl font-bold text-gray-900 mb-2">
          <Settings className="inline mr-2" size={24} />
          Hostel Settings
        </h2>
        <p className="text-gray-600 text-sm">
          Configure how students join your hostel
        </p>
      </div>

      {/* Join Code Section */}
      <div className="border rounded-lg p-4 bg-gray-50">
        <div className="flex items-center justify-between mb-4">
          <div>
            <h3 className="font-semibold text-gray-900 flex items-center gap-2">
              <Key size={18} />
              Student Join Code
            </h3>
            <p className="text-sm text-gray-600">
              Share this code with students to let them join directly
            </p>
          </div>
          <button
            onClick={handleRegenerateCode}
            className="p-2 hover:bg-gray-200 rounded-lg transition-colors"
            title="Regenerate Code"
          >
            <RotateCw size={18} />
          </button>
        </div>
        <div className="bg-white p-4 rounded border border-gray-200">
          <input
            type="text"
            value={settings.joinCode}
            readOnly
            className="w-full px-4 py-2 bg-gray-100 border border-gray-300 rounded font-mono text-center text-lg tracking-widest"
          />
          <p className="text-xs text-gray-500 mt-2">
            Click regenerate icon to create a new code
          </p>
        </div>
      </div>

      {/* Auto-Approve Section */}
      <div className="border rounded-lg p-4">
        <div className="flex items-center justify-between">
          <div>
            <h3 className="font-semibold text-gray-900">
              Auto-Approve Members
            </h3>
            <p className="text-sm text-gray-600">
              {settings.autoApprove
                ? "✓ Enabled: Students joining with code are approved immediately"
                : "✗ Disabled: You must manually approve each join request"}
            </p>
          </div>
          <input
            type="checkbox"
            checked={settings.autoApprove}
            onChange={(e) =>
              setSettings((prev) => ({
                ...prev,
                autoApprove: e.target.checked,
              }))
            }
            className="w-6 h-6 rounded border-gray-300 cursor-pointer"
          />
        </div>

        {!settings.autoApprove && (
          <div className="mt-4 bg-blue-50 border border-blue-200 rounded-lg p-3">
            <p className="text-sm text-blue-700">
              💡 Tip: When auto-approve is off, you can:
            </p>
            <ul className="text-sm text-blue-600 mt-2 space-y-1 ml-4">
              <li>• Review student profiles before accepting</li>
              <li>• Control hostel capacity</li>
              <li>• Reject invalid requests</li>
            </ul>
          </div>
        )}

        {settings.autoApprove && (
          <div className="mt-4 bg-amber-50 border border-amber-200 rounded-lg p-3">
            <p className="text-sm text-amber-700">
              ⚠️ Note: Students will be immediately added to your hostel
            </p>
          </div>
        )}
      </div>

      {/* Save Button */}
      <div className="flex gap-2 justify-end pt-4 border-t">
        <button
          onClick={fetchSettings}
          className="px-4 py-2 text-gray-700 border border-gray-300 rounded hover:bg-gray-50 transition-colors"
        >
          Cancel
        </button>
        <button
          onClick={handleSaveSettings}
          disabled={saving}
          className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700 disabled:bg-gray-400 transition-colors"
        >
          {saving ? "Saving..." : "Save Settings"}
        </button>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import toast from "react-hot-toast";
import axios from "axios";
import { CheckCircle, XCircle, Users } from "lucide-react";

export default function JoinRequestsPanel({ hostelId }) {
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState("pending");
  const [actioningId, setActioningId] = useState(null);

  useEffect(() => {
    if (hostelId) {
      fetchRequests();
    }
  }, [hostelId, filter]);

  const fetchRequests = async () => {
    setLoading(true);
    try {
      const response = await axios.get("/api/hostels/join-requests", {
        params: { hostelId, status: filter },
      });
      setRequests(response.data.requests || []);
    } catch (error) {
      console.error("Fetch error:", error);
      toast.error("Failed to fetch join requests");
    } finally {
      setLoading(false);
    }
  };

  const handleApprove = async (requestId, userId) => {
    setActioningId(requestId);
    try {
      await axios.post(
        `/api/hostels/join-requests/${requestId}/approve`,
        { hostelId, userId }
      );
      toast.success("Request approved!");
      fetchRequests();
    } catch (error) {
      console.error("Approve error:", error);
      toast.error(error.response?.data?.error || "Failed to approve");
    } finally {
      setActioningId(null);
    }
  };

  const handleReject = async (requestId, reason = "") => {
    setActioningId(requestId);
    try {
      await axios.post(
        `/api/hostels/join-requests/${requestId}/reject`,
        { reason }
      );
      toast.success("Request rejected");
      fetchRequests();
    } catch (error) {
      console.error("Reject error:", error);
      toast.error(error.response?.data?.error || "Failed to reject");
    } finally {
      setActioningId(null);
    }
  };

  return (
    <div className="bg-white rounded-lg shadow p-6">
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-gray-900 mb-4">
          <Users className="inline mr-2" size={24} />
          Join Requests
        </h2>

        {/* Filter Tabs */}
        <div className="flex gap-2 border-b">
          {["pending", "approved", "rejected"].map((status) => (
            <button
              key={status}
              onClick={() => setFilter(status)}
              className={`px-4 py-2 font-medium capitalize transition-colors border-b-2 ${
                filter === status
                  ? "border-blue-600 text-blue-600"
                  : "border-transparent text-gray-600 hover:text-gray-900"
              }`}
            >
              {status}
            </button>
          ))}
        </div>
      </div>

      {loading ? (
        <div className="text-center py-8 text-gray-500">Loading...</div>
      ) : requests.length === 0 ? (
        <div className="text-center py-8 text-gray-500">
          No {filter} join requests
        </div>
      ) : (
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="border-b">
                <th className="text-left py-3 px-4 font-semibold text-gray-700">
                  Student Name
                </th>
                <th className="text-left py-3 px-4 font-semibold text-gray-700">
                  Requested At
                </th>
                <th className="text-left py-3 px-4 font-semibold text-gray-700">
                  Status
                </th>
                {filter === "pending" && (
                  <th className="text-right py-3 px-4 font-semibold text-gray-700">
                    Actions
                  </th>
                )}
              </tr>
            </thead>
            <tbody>
              {requests.map((req) => (
                <tr key={req.id} className="border-b hover:bg-gray-50">
                  <td className="py-3 px-4">
                    <div className="font-medium text-gray-900">
                      {req.userName}
                    </div>
                    <div className="text-sm text-gray-500">{req.userId}</div>
                  </td>
                  <td className="py-3 px-4 text-sm text-gray-600">
                    {new Date(req.requestedAt).toLocaleDateString()}
                  </td>
                  <td className="py-3 px-4">
                    <span
                      className={`inline-block px-3 py-1 rounded-full text-sm font-medium ${
                        req.status === "approved"
                          ? "bg-green-100 text-green-800"
                          : req.status === "rejected"
                            ? "bg-red-100 text-red-800"
                            : "bg-yellow-100 text-yellow-800"
                      }`}
                    >
                      {req.status}
                    </span>
                  </td>
                  {filter === "pending" && (
                    <td className="py-3 px-4 text-right">
                      <div className="flex gap-2 justify-end">
                        <button
                          onClick={() => handleApprove(req.id, req.userId)}
                          disabled={actioningId === req.id}
                          className="px-3 py-1 bg-green-600 text-white text-sm rounded hover:bg-green-700 disabled:bg-gray-400 transition-colors flex items-center gap-1"
                        >
                          <CheckCircle size={16} />
                          Approve
                        </button>
                        <button
                          onClick={() => handleReject(req.id)}
                          disabled={actioningId === req.id}
                          className="px-3 py-1 bg-red-600 text-white text-sm rounded hover:bg-red-700 disabled:bg-gray-400 transition-colors flex items-center gap-1"
                        >
                          <XCircle size={16} />
                          Reject
                        </button>
                      </div>
                    </td>
                  )}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

"use client";

import { useNotification } from "@/contexts/NotificationContext";
import { useState, useRef, useEffect } from "react";
import { Bell, Check, X, Megaphone, Receipt, Wallet, Wrench, Bed, UserIcon } from "lucide-react";
import { formatDistanceToNow } from "date-fns";
import { useRouter } from "next/navigation";
import { useAuth } from "@/contexts/AuthContext";

export default function NotificationDropdown() {
  const [isOpen, setIsOpen] = useState(false);
  const { notifications, unreadCount, markAsRead, markAllRead, clearAll } = useNotification();
  const { role } = useAuth();
  const dropdownRef = useRef(null);
  const router = useRouter();

  // Close when clicking outside
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setIsOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const getIcon = (type) => {
    switch(type) {
      case "visitor_request": return <UserIcon size={16} className="text-blue-500" />;
      case "visitor_approved": return <Check size={16} className="text-blue-600" />;
      case "visitor_rejected": return <X size={16} className="text-rose-500" />;
      case "fee_due": return <Wallet size={16} className="text-orange-500" />;
      case "fee_paid": return <Receipt size={16} className="text-blue-600" />;
      case "complaint_raised":
      case "complaint_resolved": return <Wrench size={16} className="text-yellow-500" />;
      case "room_allocated": return <Bed size={16} className="text-indigo-500" />;
      case "announcement": return <Megaphone size={16} className="text-purple-500" />;
      default: return <Bell size={16} className="text-slate-500" />;
    }
  };

  const handleNotificationClick = (notif) => {
